import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Deposit = ({ onDepositSuccess }) => {
  const [crypto, setCrypto] = useState('USDT');
  const [addresses, setAddresses] = useState({});
  const [amount, setAmount] = useState('');
  const [status, setStatus] = useState('');
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) return;

    axios.get('http://localhost:5000/api/deposit/addresses', {
      headers: { Authorization: `Bearer ${token}` }
    })
    .then(res => setAddresses(res.data))
    .catch(() => setStatus('Unable to load deposit addresses.'));
  }, []);

  const handleDeposit = async (e) => {
    e.preventDefault();
    setStatus('');
    if (!amount || Number(amount) <= 0) {
      setStatus('Please enter a valid amount.');
      return;
    }
    try {
      const token = localStorage.getItem('token');
      const res = await axios.post('http://localhost:5000/api/deposit/deposit', { crypto, amount }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setStatus(`Deposit simulated. New balance: $${res.data.balance.toFixed(2)}`);
      setAmount('');
      if (onDepositSuccess) onDepositSuccess(res.data.balance);
    } catch (error) {
      setStatus(error?.response?.data?.error || 'Deposit failed.');
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(addresses[crypto] || '');
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="card">
      <div className="form-grid">
        <div className="form-group">
          <label>Select Cryptocurrency</label>
          <select value={crypto} onChange={(e) => setCrypto(e.target.value)}>
            <option value="USDT">USDT (Tether)</option>
            <option value="USDC">USDC (USD Coin)</option>
          </select>
        </div>
        
        <div className="form-group">
          <label>Deposit Address</label>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
            <input type="text" value={addresses[crypto] || 'Loading...'} readOnly style={{ flex: 1 }} />
            <button type="button" onClick={copyToClipboard} style={{ padding: '8px 12px', fontSize: '0.9rem' }}>
              {copied ? 'Copied!' : 'Copy'}
            </button>
          </div>
        </div>

        <div className="form-group">
          <label>Deposit Amount</label>
          <input type="number" placeholder="Enter amount" value={amount} onChange={(e) => setAmount(e.target.value)} />
        </div>

        <div style={{ marginTop: '16px', padding: '16px', background: 'var(--bg)', borderRadius: '8px', border: '1px solid var(--border)' }}>
          <h4 style={{ margin: '0 0 8px', fontSize: '1rem' }}>Deposit Instructions:</h4>
          <ol style={{ margin: 0, paddingLeft: '20px', fontSize: '0.9rem', color: 'var(--text-light)' }}>
            <li>Copy the deposit address above</li>
            <li>Go to your crypto wallet or exchange</li>
            <li>Send {crypto} to the copied address</li>
            <li>Enter the amount you deposited below</li>
            <li>Click "Confirm Deposit" to update your balance</li>
          </ol>
          <p style={{ margin: '8px 0 0', fontSize: '0.8rem', color: 'var(--text-light)' }}>
            Note: Balance will be updated automatically after confirmation.
          </p>
        </div>

        {status && <div className="status-message">{status}</div>}
        
        <button type="submit" onClick={handleDeposit} disabled={!amount || Number(amount) <= 0}>
          Confirm Deposit
        </button>
      </div>
    </div>
  );
};

export default Deposit;
